pages.css:
.page-02 {
  width: 1242px;
  height: 1660px;
  background-color: #F7F8FA;
  box-sizing: border-box;
  padding: 88px 96px;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  display: flex;
  flex-direction: column;
}

.page-header {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 56px;
}

.header-icon {
  font-size: 44px;
}

.header-label {
  font-size: 40px;
  font-weight: 600;
  color: #555555;
  letter-spacing: 0;
}

.page-title {
  margin-bottom: 64px;
}

.page-title p {
  margin: 0;
  font-size: 104px;
  font-weight: 900;
  line-height: 1.25;
  color: #1A1A1A;
  letter-spacing: 0;
}

.page-title p:last-child {
  color: #D32F2F;
}

.proof-list {
  display: flex;
  flex-direction: column;
  gap: 20px;
  flex: 1;
}

.proof-card {
  background-color: #FFFFFF;
  border-radius: 16px;
  padding: 32px 40px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.03);
  display: flex;
  flex-direction: column;
  gap: 12px;
  border-left: 8px solid #D32F2F;
}

.proof-tag {
  font-size: 42px;
  font-weight: 800;
  color: #1A1A1A;
  letter-spacing: 0;
}

.proof-text {
  margin: 0;
  font-size: 38px;
  line-height: 1.55;
  color: #555555;
  letter-spacing: 0;
}

.page {
  width: 1242px;
  height: 1660px;
  box-sizing: border-box;
  padding: 100px 100px 88px 100px;
  background-color: #0A0A0C;
  color: #FFFFFF;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  display: flex;
  flex-direction: column;
}

.page-header {
  display: flex;
  align-items: center;
  margin-bottom: 50px;
  font-size: 38px;
  font-weight: 600;
  color: #888888;
  letter-spacing: 0;
}

.icon {
  margin-right: 16px;
}

.title-section {
  margin-bottom: 60px;
}

.page-title {
  font-size: 110px;
  font-weight: 900;
  line-height: 1.2;
  letter-spacing: 0;
  color: #FFFFFF;
}

.metric-section {
  margin-bottom: 60px;
  padding-bottom: 40px;
  border-bottom: 2px solid #222222;
}

.metric-value {
  display: flex;
  align-items: baseline;
}

.highlight {
  font-size: 220px;
  font-weight: 900;
  color: #FF4500;
  line-height: 1;
  letter-spacing: 0;
}

.highlight-sub {
  font-size: 56px;
  font-weight: 700;
  color: #FF4500;
  margin-left: 20px;
  letter-spacing: 0;
}

.proof-list {
  display: flex;
  flex-direction: column;
  gap: 36px;
  flex: 1;
}

.proof-item {
  display: flex;
  flex-direction: column;
  gap: 16px;
  padding-left: 24px;
  border-left: 4px solid #333333;
}

.proof-tag {
  font-size: 36px;
  font-weight: 700;
  color: #0A0A0C;
  background-color: #EEEEEE;
  padding: 6px 16px;
  border-radius: 8px;
  align-self: flex-start;
  letter-spacing: 0;
}

.proof-text {
  font-size: 42px;
  line-height: 1.5;
  color: #CCCCCC;
  font-weight: 400;
  margin: 0;
  letter-spacing: 0;
}

.footnote-section {
  margin-top: 40px;
  padding-top: 30px;
  border-top: 1px solid #222222;
}

.footnote-text {
  font-size: 32px;
  color: #666666;
  line-height: 1.5;
  margin: 0;
  letter-spacing: 0;
}

.page-05 {
  width: 1242px;
  height: 1660px;
  background-color: #F4F5F7;
  color: #000;
  padding: 120px 100px;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  letter-spacing: 0;
}

.header {
  display: flex;
  align-items: center;
  margin-bottom: 60px;
}

.label {
  font-size: 38px;
  color: #555;
  font-weight: 600;
}

.icon {
  font-size: 42px;
  margin-left: 16px;
}

.title-section {
  margin-bottom: 70px;
}

.page-title {
  font-size: 132px;
  font-weight: 900;
  line-height: 1.15;
  margin: 0;
  color: #111;
}

.sub-item {
  display: flex;
  flex-direction: column;
  background-color: #FFFFFF;
  padding: 48px;
  border-radius: 16px;
  margin-bottom: 70px;
  border-left: 12px solid #E63946;
  box-shadow: 0 20px 40px rgba(0,0,0,0.04);
}

.proof-tag {
  display: inline-block;
  background-color: #E63946;
  color: #FFFFFF;
  font-size: 36px;
  padding: 8px 24px;
  border-radius: 8px;
  font-weight: bold;
  margin-bottom: 24px;
  align-self: flex-start;
}

.proof-text {
  font-size: 42px;
  line-height: 1.6;
  color: #222;
  margin: 0;
  font-weight: 500;
}

.steps-container {
  flex: 1;
}

.proof-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 40px;
}

.proof-item {
  display: flex;
  align-items: flex-start;
  background-color: transparent;
  border-bottom: 2px solid #E5E7EB;
  padding-bottom: 40px;
}

.proof-item:last-child {
  border-bottom: none;
  padding-bottom: 0;
}

.step-num {
  font-size: 72px;
  font-weight: 900;
  color: #E63946;
  margin-right: 36px;
  line-height: 0.9;
  font-family: Arial, sans-serif;
}

.step-text {
  font-size: 40px;
  line-height: 1.6;
  color: #333;
  margin: 0;
  flex: 1;
}

.page-06 {
  width: 1242px;
  height: 1660px;
  background-color: #0A0A0A;
  color: #FFFFFF;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  box-sizing: border-box;
  padding: 100px;
  display: flex;
  flex-direction: column;
  position: relative;
}
.page-header {
  display: flex;
  align-items: center;
  gap: 20px;
  margin-bottom: 120px;
}
.header-icon {
  font-size: 48px;
}
.header-label {
  font-size: 40px;
  color: #888888;
  font-weight: 500;
  letter-spacing: 0;
}
.title-section {
  margin-bottom: 120px;
}
.page-title {
  font-size: 132px;
  font-weight: 900;
  line-height: 1.25;
  color: #FFFFFF;
  letter-spacing: 0;
}
.action-section {
  display: flex;
  flex-direction: column;
  gap: 48px;
  flex: 1;
}
.action-item {
  background-color: #1A1A1A;
  border-radius: 16px;
  padding: 64px;
  border-left: 12px solid #FF4500;
  display: flex;
  flex-direction: column;
  gap: 24px;
}
.action-item:nth-child(2) {
  border-left-color: #FFD700;
}
.action-tag {
  font-size: 46px;
  font-weight: 800;
  color: #FFFFFF;
  letter-spacing: 0;
}
.action-text {
  font-size: 42px;
  line-height: 1.6;
  color: #CCCCCC;
  margin: 0;
  letter-spacing: 0;
}
